package com.agmsolutions.fabrick_test.service;import com.agmsolutions.fabrick_test.Model.dto.BalanceDto;import com.agmsolutions.fabrick_test.Model.dto.MoneyTransferBodyDto;import com.agmsolutions.fabrick_test.Model.dto.MoneyTransferResponseDto;import com.agmsolutions.fabrick_test.Model.dto.TransactionDto;import com.agmsolutions.fabrick_test.configurations.FabrickApiRest;import com.agmsolutions.fabrick_test.configurations.Response;import com.agmsolutions.fabrick_test.configurations.ResponseList;import lombok.AllArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.core.ParameterizedTypeReference;import org.springframework.stereotype.Service;import org.springframework.web.client.ResourceAccessException;import java.time.LocalDate;import java.time.LocalDateTime;import java.util.List;@Slf4j@Service@AllArgsConstructorpublic class AccountService {    private final FabrickApiRest fabrickApiRest;    public BalanceDto getBalance(Long accountId){        log.info("INFO {} - get balance for account {}", LocalDateTime.now(), accountId);                log.info("INFO {} - api call Fabrick GET /api/gbs/banking/v4.0/accounts/{accountId}/balance", LocalDateTime.now());        Response<BalanceDto> res= fabrickApiRest.getRestClient()                .get()                .uri("/api/gbs/banking/v4.0/accounts/{accountId}/balance", accountId)                .retrieve()                .body(new ParameterizedTypeReference<>() {});        if (res == null || res.getPayload() == null)            throw new ResourceAccessException("Errore chiamata Fabrick");        log.info("INFO {} - GET returned payload: {}", LocalDateTime.now(), res.getPayload());        return res.getPayload();    }    public List<TransactionDto> getTransactions(Long accountId, LocalDate fromDate, LocalDate toDate){        log.info("INFO {} - get transactions for account {} from {} to {}", LocalDateTime.now(), accountId, fromDate, toDate);        log.info("INFO {} - api call Fabrick GET /api/gbs/banking/v4.0/accounts/{accountId}/transactions?fromAccountingDate={from}&toAccountingDate={to}", LocalDateTime.now());        Response<ResponseList<TransactionDto>> res = fabrickApiRest.getRestClient()                .get()                .uri("/api/gbs/banking/v4.0/accounts/{accountId}/transactions?fromAccountingDate={from}&toAccountingDate={to}", accountId, fromDate, toDate)                .retrieve()                .body(new ParameterizedTypeReference<>() {});        if (res == null || res.getPayload() == null)            throw new ResourceAccessException("Errore chiamata Fabrick");        log.info("INFO {} - GET returned payload: {}", LocalDateTime.now(), res.getPayload());        return res.getPayload().getList();    }    public MoneyTransferResponseDto createMoneyTransfer(Long accountId, MoneyTransferBodyDto body){        log.info("INFO {} - create new money transfer from account {}, body: {}", LocalDateTime.now(), accountId, body);        log.info("INFO {} - api call Fabrick POST /api/gbs/banking/v4.0/accounts/{accountId}/payments/money-transfers", LocalDateTime.now());        Response<MoneyTransferResponseDto> res = fabrickApiRest.getRestClient()                .post()                .uri("/api/gbs/banking/v4.0/accounts/{accountId}/payments/money-transfers", accountId)                .body(body)                .retrieve()                .body(new ParameterizedTypeReference<>() {});        if (res == null || res.getPayload() == null)            throw new ResourceAccessException("Errore chiamata Fabrick");        log.info("INFO {} - POST returned payload: {}", LocalDateTime.now(), res.getPayload());        return res.getPayload();    }}